value.Contact Phone:
='{{
(() => {
  const raw = String($('Edit Fields').item.json["phone number"] || '');

  // Remove everything except digits and +
  let phone = raw.replace(/[^0-9+]/g, '');

  // Convert leading 00 to +
  if (phone.startsWith('00')) {
    phone = '+' + phone.slice(2);
  }

  // Add + if missing
  if (!phone.startsWith('+') && phone.length > 0) {
    phone = '+' + phone;
  }

  return phone;
})()
}}

